// List the client sites you want to watch.
// label = friendly name shown in the alert, url = full URL to check.
// expectStatus is optional (default 200). timeoutMs caps each request.
const SITES = [
  { label: 'Client A', url: 'https://example.com' },
  { label: 'Client B', url: 'https://shop.example.org' },
  { label: 'Client C', url: 'https://example.net/health' }
];

// How slow (ms) counts as a 'slow' warning even when the site is up.
const SLOW_MS = 3000;
const TIMEOUT_MS = 10000;

return SITES.map((s) => ({
  json: {
    label: s.label,
    url: s.url,
    expectStatus: s.expectStatus || 200,
    slowMs: SLOW_MS,
    timeoutMs: TIMEOUT_MS
  }
}));

// Evaluate each response and emit only sites that are DOWN or SLOW.
// 'Check site' runs once per incoming item; pair each result with its input.
const results = $input.all();
const out = [];

for (const item of results) {
  const cfg = item.json;
  // With fullResponse + neverError, status code lives in statusCode.
  const status = cfg.statusCode ?? (cfg.response && cfg.response.statusCode);
  const label = cfg.label || cfg.url;
  const url = cfg.url;
  const expect = cfg.expectStatus || 200;

  // n8n exposes timing only when enabled; fall back to undefined.
  let problem = null;
  if (status === undefined || status === null) {
    problem = `\u26D4 ${label} no responde (timeout o DNS)`;
  } else if (status >= 500) {
    problem = `\u26D4 ${label} caído — HTTP ${status}`;
  } else if (status !== expect && status >= 400) {
    problem = `\u26A0 ${label} responde HTTP ${status} (esperaba ${expect})`;
  }

  if (problem) {
    out.push({ json: { down: true, label, url, status: status ?? 'sin respuesta', text: `${problem}\n${url}` } });
  }
}

return out;
